1	/* ==========================================================================
2	   app.js — GEX/VEX Multi-Widget Dashboard v3
3	   ==========================================================================
4	   Key change: ZERO-FLICKER updates.
5	     - fetchWidgetData() never clears the table
6	     - Compares fetched_at timestamps; only re-renders if data is newer
7	     - Shows "Loading..." only on first load when no data exists yet
8	     - Handles 202 (pending) gracefully with a subtle indicator
9	   ========================================================================== */
10	
11	(function () {
12	    "use strict";
13	
14	    // ======================================================================
15	    // Global State
16	    // ======================================================================
17	
18	    let widgetCounter = 0;
19	    const widgets = {};
20	    let globalApiCalls = 0;
21	    let colorSettings = loadColorSettings();
22	
23	    function defaultColorSettings() {
24	        return {
25	            extremePosFill:  "#1a5c2a",
26	            mediumPosFill:   "#0d3d4a",
27	            mediumNegFill:   "#4a1a2e",
28	            extremeNegFill:  "#6b1a4a",
29	            neutralFill:     "#0f1520",
30	            extremePosText:  "#fde047",
31	            mediumPosText:   "#4ade80",
32	            mediumNegText:   "#f87171",
33	            extremeNegText:  "#f472b6",
34	            neutralText:     "#475569",
35	            threshold: 65,
36	            refreshInterval: 60,
37	        };
38	    }
39	
40	    function loadColorSettings() {
41	        try {
42	            const saved = localStorage.getItem("gexvex_colors_v2");
43	            if (saved) return { ...defaultColorSettings(), ...JSON.parse(saved) };
44	        } catch {}
45	        return defaultColorSettings();
46	    }
47	
48	    function saveColorSettings() {
49	        try { localStorage.setItem("gexvex_colors_v2", JSON.stringify(colorSettings)); } catch {}
50	    }
51	
52	    // ======================================================================
53	    // 4-Tier Color Engine
54	    // ======================================================================
55	
56	    function hexToRgb(hex) {
57	        hex = hex.replace("#", "");
58	        if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
59	        return {
60	            r: parseInt(hex.slice(0, 2), 16),
61	            g: parseInt(hex.slice(2, 4), 16),
62	            b: parseInt(hex.slice(4, 6), 16),
63	        };
64	    }
65	
66	    function lerpColor(hexA, hexB, t, alpha = 1) {
67	        const a = hexToRgb(hexA);
68	        const b = hexToRgb(hexB);
69	        const r = Math.round(a.r + (b.r - a.r) * t);
70	        const g = Math.round(a.g + (b.g - a.g) * t);
71	        const bl = Math.round(a.b + (b.b - a.b) * t);
72	        return `rgba(${r}, ${g}, ${bl}, ${alpha})`;
73	    }
74	
75	    function valueToColors(value, maxAbs) {
76	        const cs = colorSettings;
77	        const neutral = cs.neutralFill;
78	
79	        if (maxAbs === 0 || value === 0) {
80	            return { bg: neutral, fg: cs.neutralText };
81	        }
82	
83	        const ratio = Math.max(-1, Math.min(1, value / maxAbs));
84	        const absRatio = Math.abs(ratio);
85	        const thr = cs.threshold / 100;
86	
87	        let tierFill, tierText, intensity;
88	
89	        if (ratio > 0) {
90	            if (absRatio >= thr) {
91	                tierFill = cs.extremePosFill;
92	                tierText = cs.extremePosText;
93	                intensity = thr < 1 ? (absRatio - thr) / (1 - thr) : 1;
94	            } else {
95	                tierFill = cs.mediumPosFill;
96	                tierText = cs.mediumPosText;
97	                intensity = thr > 0 ? absRatio / thr : 1;
98	            }
99	        } else {
100	            if (absRatio >= thr) {
101	                tierFill = cs.extremeNegFill;
102	                tierText = cs.extremeNegText;
103	                intensity = thr < 1 ? (absRatio - thr) / (1 - thr) : 1;
104	            } else {
105	                tierFill = cs.mediumNegFill;
106	                tierText = cs.mediumNegText;
107	                intensity = thr > 0 ? absRatio / thr : 1;
108	            }
109	        }
110	
111	        intensity = Math.pow(intensity, 0.7);
112	        const alpha = 0.35 + intensity * 0.65;
113	        const bg = lerpColor(neutral, tierFill, intensity, alpha);
114	        const fg = intensity < 0.08 ? cs.neutralText : tierText;
115	        return { bg, fg };
116	    }
117	
118	    // ======================================================================
119	    // Formatters
120	    // ======================================================================
121	
122	    function fmtDollarK(v) {
123	        const a = Math.abs(v);
124	        let s;
125	        if (a >= 1e6)      s = (a / 1e6).toFixed(1) + "M";
126	        else if (a >= 1e3)  s = (a / 1e3).toFixed(1) + "K";
127	        else                s = a.toFixed(1);
128	        return (v > 0 ? "$" : v < 0 ? "-$" : "$") + s;
129	    }
130	
131	    function fmtExp(d) {
132	        const p = d.split("-");
133	        return p[1] + "/" + p[2];
134	    }
135	
136	    function fmtTimestamp(isoStr) {
137	        // "2026-04-01T14:32:05" → "14:32:05"
138	        if (!isoStr) return "--:--:--";
139	        try {
140	            const d = new Date(isoStr);
141	            return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
142	        } catch { return isoStr; }
143	    }
144	
145	    function getRow(matrix, s) {
146	        return matrix[String(s)] || matrix[Number(s).toFixed(1)] || matrix[Number(s).toFixed(2)] || {};
147	    }
148	
149	    // ======================================================================
150	    // Subscription API Helpers
151	    // ======================================================================
152	
153	    async function apiSubscribe(symbol) {
154	        try {
155	            await fetch("/api/subscribe", {
156	                method: "POST",
157	                headers: { "Content-Type": "application/json" },
158	                body: JSON.stringify({ symbol: symbol.toUpperCase() }),
159	            });
160	        } catch (e) {
161	            console.warn("Subscribe failed:", e);
162	        }
163	    }
164	
165	    async function apiUnsubscribe(symbol) {
166	        // Only unsubscribe if no other widget is watching this symbol
167	        const othersWatching = Object.values(widgets).some(
168	            (w) => w.symbol === symbol.toUpperCase() && w.el  // alive widget
169	        );
170	        if (othersWatching) return;
171	
172	        try {
173	            await fetch(`/api/subscribe/${symbol.toUpperCase()}`, { method: "DELETE" });
174	        } catch (e) {
175	            console.warn("Unsubscribe failed:", e);
176	        }
177	    }
178	
179	    // ======================================================================
180	    // Widget Lifecycle
181	    // ======================================================================
182	
183	    function createWidget(symbol = "NVDA") {
184	        const id = ++widgetCounter;
185	        const state = {
186	            id,
187	            symbol: symbol.toUpperCase(),
188	            mode: "gex",
189	            data: null,                 // last rendered data
190	            lastFetchedAt: null,        // timestamp of last rendered data
191	            countdown: colorSettings.refreshInterval,
192	            paused: false,
193	            timer: null,
194	            el: null,
195	            hasTable: false,            // true once first table is rendered
196	        };
197	        widgets[id] = state;
198	        buildWidgetDOM(state);
199	        apiSubscribe(state.symbol);
200	        fetchWidgetData(state);
201	        startWidgetTimer(state);
202	        return state;
203	    }
204	
205	    function destroyWidget(id) {
206	        const w = widgets[id];
207	        if (!w) return;
208	        clearInterval(w.timer);
209	        if (w._pendingRetry) clearTimeout(w._pendingRetry);
210	        const sym = w.symbol;
211	        w.el.remove();
212	        delete widgets[id];
213	        // Unsubscribe after deletion so the "othersWatching" check works
214	        apiUnsubscribe(sym);
215	    }
216	
217	    // ======================================================================
218	    // Widget DOM
219	    // ======================================================================
220	
221	    function buildWidgetDOM(w) {
222	        const el = document.createElement("div");
223	        el.className = "widget";
224	        el.dataset.wid = w.id;
225	
226	        el.innerHTML = `
227	        <div class="widget__head">
228	            <form class="wform" data-wid="${w.id}">
229	                <input type="text" class="widget__ticker-input" value="${w.symbol}"
230	                       maxlength="6" spellcheck="false" autocomplete="off">
231	                <button type="submit" class="btn-sm">Go</button>
232	            </form>
233	            <div class="wquote" data-wid="${w.id}"></div>
234	            <div class="mode-tabs" data-wid="${w.id}">
235	                <button class="mode-tab active" data-mode="gex">GEX</button>
236	                <button class="mode-tab" data-mode="vex">VEX</button>
237	            </div>
238	            <span class="widget__spacer"></span>
239	            <span class="widget__fetched-at" data-wid="${w.id}" title="Data timestamp">--:--:--</span>
240	            <span class="widget__fetch-indicator" data-wid="${w.id}"></span>
241	            <span class="widget__timer" data-wid="${w.id}">${w.countdown}s</span>
242	            <button class="btn-sm wpause" data-wid="${w.id}" title="Pause">⏸</button>
243	            <button class="btn-sm wrefresh" data-wid="${w.id}" title="Refresh">↻</button>
244	            <button class="widget__close" data-wid="${w.id}" title="Close widget">✕</button>
245	        </div>
246	        <div class="widget__body" data-wid="${w.id}">
247	            <div class="status-msg"><span class="spinner"></span>Waiting for data...</div>
248	        </div>`;
249	
250	        // --- Events ---
251	        const form = el.querySelector(".wform");
252	        form.addEventListener("submit", (e) => {
253	            e.preventDefault();
254	            const val = form.querySelector("input").value.trim().toUpperCase();
255	            if (val && val !== w.symbol) {
256	                const oldSym = w.symbol;
257	                w.symbol = val;
258	                w.data = null;
259	                w.lastFetchedAt = null;
260	                w.hasTable = false;
261	                // Show loading for new symbol
262	                el.querySelector(".widget__body").innerHTML =
263	                    `<div class="status-msg"><span class="spinner"></span>Waiting for data...</div>`;
264	                apiUnsubscribe(oldSym);
265	                apiSubscribe(val);
266	                fetchWidgetData(w);
267	                restartWidgetTimer(w);
268	            }
269	        });
270	
271	        el.querySelector(".widget__close").addEventListener("click", () => destroyWidget(w.id));
272	
273	        el.querySelectorAll(".mode-tab").forEach((tab) => {
274	            tab.addEventListener("click", () => {
275	                const mode = tab.dataset.mode;
276	                if (mode === w.mode) return;
277	                w.mode = mode;
278	                w.lastFetchedAt = null;  // force re-render on mode switch
279	                el.querySelectorAll(".mode-tab").forEach((t) =>
280	                    t.classList.toggle("active", t.dataset.mode === mode));
281	                fetchWidgetData(w);
282	                restartWidgetTimer(w);
283	            });
284	        });
285	
286	        el.querySelector(".wpause").addEventListener("click", () => {
287	            w.paused = !w.paused;
288	            el.querySelector(".wpause").textContent = w.paused ? "▶" : "⏸";
289	            updateWidgetTimerDisplay(w);
290	        });
291	
292	        el.querySelector(".wrefresh").addEventListener("click", () => {
293	            fetchWidgetData(w);
294	            restartWidgetTimer(w);
295	        });
296	
297	        w.el = el;
298	        document.getElementById("workspace").appendChild(el);
299	    }
300	
301	    // ======================================================================
302	    // Data Fetching (FLICKER-FREE)
303	    // ======================================================================
304	
305	    async function fetchWidgetData(w) {
306	        // Show a subtle spinner indicator in the header — NOT in the table body
307	        const indicator = w.el.querySelector(".widget__fetch-indicator");
308	        indicator.innerHTML = '<span class="spinner-sm"></span>';
309	
310	        try {
311	            const resp = await fetch(`/api/matrix/${w.symbol}?mode=${w.mode}`);
312	            const data = await resp.json();
313	
314	            // Handle 202 (pending — background thread hasn't cached this yet)
315	            if (resp.status === 202 || data.pending) {
316	                if (!w.hasTable) {
317	                    w.el.querySelector(".widget__body").innerHTML =
318	                        `<div class="status-msg"><span class="spinner"></span>${data.message || "Fetching..."}</div>`;
319	                }
320	                indicator.innerHTML = '<span class="pending-dot" title="Waiting for background data">●</span>';
321	
322	                // FAST RETRY: poll again in 2s instead of waiting for the full timer
323	                if (!w._pendingRetry) {
324	                    w._pendingRetry = setTimeout(() => {
325	                        w._pendingRetry = null;
326	                        fetchWidgetData(w);
327	                    }, 2000);
328	                }
329	                return;
330	            }
331	
332	            // Clear any pending retry since we got real data
333	            if (w._pendingRetry) {
334	                clearTimeout(w._pendingRetry);
335	                w._pendingRetry = null;
336	            }
337	
338	            // Handle error responses
339	            if (data.error) {
340	                if (!w.hasTable) {
341	                    w.el.querySelector(".widget__body").innerHTML =
342	                        `<div class="status-msg error">${data.error}</div>`;
343	                }
344	                indicator.innerHTML = "";
345	                return;
346	            }
347	
348	            // --- KEY: Only re-render if fetched_at changed ---
349	            const newTimestamp = data.fetched_at || null;
350	            if (newTimestamp && newTimestamp === w.lastFetchedAt && w.hasTable) {
351	                // Data hasn't changed — skip re-render entirely
352	                indicator.innerHTML = "";
353	                updateQuoteFromData(w, data);
354	                updateFetchedAtDisplay(w, newTimestamp);
355	                return;
356	            }
357	
358	            // New data — render
359	            w.data = data;
360	            w.lastFetchedAt = newTimestamp;
361	
362	            renderQuoteChip(w, data.quote);
363	            renderHeatmap(w, data);
364	            updateFetchedAtDisplay(w, newTimestamp);
365	
366	            if (data.api_calls !== undefined) {
367	                globalApiCalls = data.api_calls;
368	                document.getElementById("global-api").textContent = `API calls: ${globalApiCalls}`;
369	            }
370	        } catch (err) {
371	            // Network error — keep existing table, show error in indicator only
372	            if (!w.hasTable) {
373	                w.el.querySelector(".widget__body").innerHTML =
374	                    `<div class="status-msg error">Error: ${err.message}</div>`;
375	            }
376	            console.error("Fetch error:", err);
377	        }
378	
379	        indicator.innerHTML = "";
380	    }
381	
382	    function updateFetchedAtDisplay(w, isoStr) {
383	        const el = w.el.querySelector(".widget__fetched-at");
384	        if (el) el.textContent = fmtTimestamp(isoStr);
385	    }
386	
387	    function updateQuoteFromData(w, data) {
388	        // Light update — just quote chip, no table re-render
389	        if (data.quote) renderQuoteChip(w, data.quote);
390	    }
391	
392	    // ======================================================================
393	    // Rendering (unchanged core, but sets w.hasTable flag)
394	    // ======================================================================
395	
396	    function renderQuoteChip(w, quote) {
397	        const chip = w.el.querySelector(".wquote");
398	        if (!quote || !quote.last) { chip.innerHTML = ""; return; }
399	        const cls = quote.change >= 0 ? "up" : "down";
400	        const sign = quote.change >= 0 ? "+" : "";
401	        chip.innerHTML = `
402	            <span class="wquote__sym">${quote.symbol}</span>
403	            <span class="wquote__dot"></span>
404	            <span class="wquote__price">$${quote.last.toFixed(2)}</span>
405	            <span class="wquote__chg ${cls}">${sign}${quote.change.toFixed(2)} (${sign}${quote.change_pct.toFixed(2)}%)</span>
406	        `;
407	    }
408	
409	    function renderHeatmap(w, data) {
410	        const body = w.el.querySelector(".widget__body");
411	        const { expirations, strikes, matrix, exp_totals, pin_strike, quote } = data;
412	        const spot = quote.last;
413	
414	        let maxAbs = 0;
415	        for (const s of strikes) {
416	            const row = getRow(matrix, s);
417	            for (const exp of expirations) {
418	                const v = Math.abs(row[exp] || 0);
419	                if (v > maxAbs) maxAbs = v;
420	            }
421	        }
422	
423	        let closestStrike = strikes[0], closestDist = Infinity;
424	        for (const s of strikes) {
425	            const d = Math.abs(s - spot);
426	            if (d < closestDist) { closestDist = d; closestStrike = s; }
427	        }
428	
429	        const sortedStrikes = [...strikes].sort((a, b) => b - a);
430	
431	        let html = '<table class="heatmap"><thead><tr>';
432	        html += '<th><span>Strike</span><div class="col-resize"></div></th>';
433	        for (const exp of expirations) {
434	            html += `<th><span>${fmtExp(exp)}</span><div class="col-resize"></div></th>`;
435	        }
436	        html += '<th><span>Total</span></th></tr></thead><tbody>';
437	
438	        for (const strike of sortedStrikes) {
439	            const row = getRow(matrix, strike);
440	            const isCurrent = strike === closestStrike;
441	            const isPin = strike === pin_strike;
442	            let cls = "";
443	            if (isCurrent) cls += " row--current";
444	            if (isPin) cls += " row--pin";
445	
446	            html += `<tr class="${cls}" data-strike="${strike}">`;
447	            html += `<td>${strike.toFixed(1)}</td>`;
448	
449	            for (const exp of expirations) {
450	                const val = row[exp] || 0;
451	                const { bg, fg } = valueToColors(val, maxAbs);
452	                html += `<td style="background:${bg};color:${fg}">${fmtDollarK(val)}</td>`;
453	            }
454	
455	            const total = row.total || 0;
456	            const totalMax = maxAbs * Math.max(1, expirations.length * 0.35);
457	            const { bg: tbg, fg: tfg } = valueToColors(total, totalMax);
458	            html += `<td style="background:${tbg};color:${tfg}">${fmtDollarK(total)}</td>`;
459	            html += '</tr>';
460	        }
461	
462	        html += '</tbody><tfoot><tr><td>TOTAL</td>';
463	        for (const exp of expirations) {
464	            const val = exp_totals[exp] || 0;
465	            const { fg } = valueToColors(val, maxAbs);
466	            html += `<td style="color:${fg}">${fmtDollarK(val)}</td>`;
467	        }
468	        const gt = exp_totals.total || 0;
469	        const { fg: gtFg } = valueToColors(gt, maxAbs);
470	        html += `<td style="color:${gtFg}">${fmtDollarK(gt)}</td>`;
471	        html += '</tr></tfoot></table>';
472	
473	        body.innerHTML = html;
474	        w.hasTable = true;
475	
476	        // Scroll to current price row (only on first render or symbol change)
477	        if (!w._scrolledOnce || !w._lastScrollSymbol || w._lastScrollSymbol !== w.symbol) {
478	            requestAnimationFrame(() => {
479	                const row = body.querySelector("tr.row--current");
480	                if (row) row.scrollIntoView({ block: "center", behavior: "instant" });
481	            });
482	            w._scrolledOnce = true;
483	            w._lastScrollSymbol = w.symbol;
484	        }
485	
486	        initColumnResize(body);
487	    }
488	
489	    // ======================================================================
490	    // Column Resizing
491	    // ======================================================================
492	
493	    function initColumnResize(container) {
494	        container.querySelectorAll(".col-resize").forEach((handle) => {
495	            handle.addEventListener("mousedown", (e) => {
496	                e.preventDefault();
497	                const th = handle.parentElement;
498	                const table = container.querySelector("table");
499	                const startX = e.clientX;
500	                const startWidth = th.offsetWidth;
501	                handle.classList.add("active");
502	
503	                if (!table.dataset.colsFixed) {
504	                    table.querySelectorAll("thead th").forEach((t) => { t.style.width = t.offsetWidth + "px"; });
505	                    table.style.tableLayout = "fixed";
506	                    table.dataset.colsFixed = "1";
507	                }
508	
509	                function onMove(ev) {
510	                    const newW = Math.max(50, startWidth + (ev.clientX - startX));
511	                    th.style.width = newW + "px";
512	                    th.style.minWidth = newW + "px";
513	                }
514	                function onUp() {
515	                    handle.classList.remove("active");
516	                    document.removeEventListener("mousemove", onMove);
517	                    document.removeEventListener("mouseup", onUp);
518	                }
519	                document.addEventListener("mousemove", onMove);
520	                document.addEventListener("mouseup", onUp);
521	            });
522	        });
523	    }
524	
525	    // ======================================================================
526	    // Widget Timers
527	    // ======================================================================
528	
529	    function startWidgetTimer(w) {
530	        w.countdown = colorSettings.refreshInterval;
531	        w.timer = setInterval(() => {
532	            if (w.paused) return;
533	            w.countdown--;
534	            updateWidgetTimerDisplay(w);
535	            if (w.countdown <= 0) {
536	                fetchWidgetData(w);
537	                w.countdown = colorSettings.refreshInterval;
538	            }
539	        }, 1000);
540	    }
541	
542	    function restartWidgetTimer(w) {
543	        clearInterval(w.timer);
544	        w.countdown = colorSettings.refreshInterval;
545	        updateWidgetTimerDisplay(w);
546	        startWidgetTimer(w);
547	    }
548	
549	    function updateWidgetTimerDisplay(w) {
550	        const el = w.el.querySelector(".widget__timer");
551	        if (el) el.textContent = w.paused ? "PAUSED" : `${w.countdown}s`;
552	    }
553	
554	    // ======================================================================
555	    // Settings Modal (unchanged from v2.1)
556	    // ======================================================================
557	
558	    function openSettings() {
559	        document.getElementById("modal-overlay").classList.add("open");
560	        populateSettingsForm();
561	    }
562	
563	    function closeSettings() {
564	        document.getElementById("modal-overlay").classList.remove("open");
565	    }
566	
567	    function populateSettingsForm() {
568	        const cs = colorSettings;
569	        document.getElementById("s-ext-pos-fill").value = cs.extremePosFill;
570	        document.getElementById("s-ext-pos-text").value = cs.extremePosText;
571	        document.getElementById("s-med-pos-fill").value = cs.mediumPosFill;
572	        document.getElementById("s-med-pos-text").value = cs.mediumPosText;
573	        document.getElementById("s-med-neg-fill").value = cs.mediumNegFill;
574	        document.getElementById("s-med-neg-text").value = cs.mediumNegText;
575	        document.getElementById("s-ext-neg-fill").value = cs.extremeNegFill;
576	        document.getElementById("s-ext-neg-text").value = cs.extremeNegText;
577	        document.getElementById("s-neutral-fill").value = cs.neutralFill;
578	        document.getElementById("s-neutral-text").value = cs.neutralText;
579	        document.getElementById("s-threshold").value = cs.threshold;
580	        document.getElementById("s-threshold-val").textContent = cs.threshold + "%";
581	        document.getElementById("s-refresh").value = cs.refreshInterval;
582	        document.getElementById("s-refresh-val").textContent = cs.refreshInterval + "s";
583	        updateSettingsPreview();
584	    }
585	
586	    function updateSettingsPreview() {
587	        const preview = document.getElementById("color-preview");
588	        if (!preview) return;
589	        preview.innerHTML = "";
590	
591	        const formCS = {
592	            extremePosFill:  document.getElementById("s-ext-pos-fill").value,
593	            mediumPosFill:   document.getElementById("s-med-pos-fill").value,
594	            mediumNegFill:   document.getElementById("s-med-neg-fill").value,
595	            extremeNegFill:  document.getElementById("s-ext-neg-fill").value,
596	            neutralFill:     document.getElementById("s-neutral-fill").value,
597	            extremePosText:  document.getElementById("s-ext-pos-text").value,
598	            mediumPosText:   document.getElementById("s-med-pos-text").value,
